import { useState } from "react";
import { useNavigate } from "react-router-dom";
import API from "../services/api";

function AddPlayer() {
  const [formData, setFormData] = useState({
    name: "",
    team: "",
    role: "Batsman",
    runs: 0,
    wickets: 0,
  });
  const [error, setError] = useState("");
  const navigate = useNavigate();

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await API.post("/players", formData);
      alert("Player added successfully!");
      navigate("/players");
    } catch (err) {
      setError(err.response?.data?.message || "Failed to add player");
    }
  };

  return (
    <div className="auth-card" style={{ maxWidth: '500px' }}>
      <h2>Add New Player</h2>
      {error && <p className="error-msg">{error}</p>}
      <form onSubmit={handleSubmit}>
        <div className="input-group">
          <label>Player Name</label>
          <input type="text" name="name" value={formData.name} onChange={handleChange} required />
        </div>
        <div className="input-group">
          <label>Team</label>
          <input type="text" name="team" value={formData.team} onChange={handleChange} required />
        </div>
        <div className="input-group">
          <label>Role</label>
          <select name="role" value={formData.role} onChange={handleChange} style={{ width: '100%', padding: '12px', borderRadius: '8px', border: '1px solid #ddd' }}>
            <option value="Batsman">Batsman</option>
            <option value="Bowler">Bowler</option>
            <option value="All-rounder">All-rounder</option>
            <option value="Wicketkeeper">Wicketkeeper</option>
          </select>
        </div>
        <div className="input-group">
          <label>Total Runs</label>
          <input type="number" name="runs" value={formData.runs} onChange={handleChange} />
        </div>
        <div className="input-group">
          <label>Total Wickets</label>
          <input type="number" name="wickets" value={formData.wickets} onChange={handleChange} />
        </div>
        <button type="submit" className="auth-btn">Save Player</button>
      </form>
    </div>
  );
}

export default AddPlayer;
